'use client';
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { supabase } from '../../lib/supabaseClient';

export default function AuthPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isSigningIn, setIsSigningIn] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');
  const router = useRouter();

  const handleAuth = async (e) => {
    e.preventDefault();
    setError('');
    setMessage('');

    if (isSigningIn) {
      const { error } = await supabase.auth.signInWithPassword({ email, password });
      if (error) return setError(error.message);

      const { data: { session } } = await supabase.auth.getSession();
      if (session) {
        router.push('/feed');
      }

    } else {
      const { data, error: signUpError } = await supabase.auth.signUp({
        email,
        password,
      });

      if (signUpError) {
        return setError(signUpError.message);
      }

      if (!data?.user?.id) {
        setMessage('Signup successful! Please check your email to confirm your address.');
        return;
      }

      const { error: insertError } = await supabase.from('profiles').insert([
        {
          id: data.user.id,
          email: data.user.email,
          created_at: new Date().toISOString(),
        },
      ]);

      if (insertError) {
        console.error('Error inserting into profiles table:', insertError);
        return setError('Error creating user profile.');
      }

      setMessage('Account created! Please check your email to verify your address.');
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4">
      <h1 className="text-2xl font-semibold mb-4">
        {isSigningIn ? 'Sign In' : 'Sign Up'}
      </h1>

      <form onSubmit={handleAuth} className="flex flex-col gap-3 w-full max-w-sm">
        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          className="border px-3 py-2 rounded"
          required
        />
        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          className="border px-3 py-2 rounded"
          required
        />
        <button type="submit" className="bg-black text-white py-2 rounded hover:bg-gray-800 transition">
          {isSigningIn ? 'Sign In' : 'Sign Up'}
        </button>
      </form>

      {error && <p className="text-red-500 text-sm mt-3">{error}</p>}
      {message && <p className="text-green-600 text-sm mt-3">{message}</p>}

      <button
        onClick={() => {
          setIsSigningIn(!isSigningIn);
          setError('');
          setMessage('');
        }}
        className="text-sm text-blue-600 mt-4"
      >
        {isSigningIn
          ? 'Need an account? Sign up'
          : 'Already have an account? Sign in'}
      </button>
    </div>
  );
}
